SELECT (SELECT id FROM post_types WHERE slug='custom_fields' LIMIT 1), 'Vídeos', 'template-jobs-videos', 'published', '{"template": true, "field_type": ["text", "editor"], "fields": [{"name": "URL", "value": "", "type": "text"}, {"name": "URLs adicionais (JSON)", "value": "", "type": "editor"}]}', 0, 0
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug='template-jobs-videos');
